import { forwardRef, useId } from "react";
import { Label as AriaLabel, Text } from "react-aria-components";
import { CheckboxGroup, type CheckboxGroupProps } from "../CheckboxGroup";
import { Legend } from "../Legend";
import type { LegendCustomProps } from "../Legend";
import { Hint } from "../Hint";
import type { HintCustomProps } from "../Hint";
import { ValidationMessage } from "../ValidationMessage";
import type {
  ValidationMessageValidProps,
  ValidationMessageInvalidProps,
} from "../ValidationMessage";
import { CheckboxTile } from "../CheckboxTile";
import { Checkbox } from "../Checkbox";
import { _CheckboxCompact } from "./components/_CheckboxCompact";
import * as styles from "./CheckboxFieldset.css";
import { clsx } from "clsx";
import type {
  TileItem,
  TextItem,
  CompactItem,
} from "./CheckboxFieldset.config";

export type CheckboxFieldsetLegend = Omit<LegendCustomProps, "asChild">;

export type CheckboxFieldsetHint = HintCustomProps;

export type CheckboxFieldsetValidationMessage =
  | ValidationMessageValidProps
  | ValidationMessageInvalidProps;

/**
 * Props specific to the tile variant
 */
interface TileVariantProps {
  /**
   * The visual variant of the checkbox group.
   * `tile`: Checkboxes inside tiles with individual borders (CheckboxTile)
   */
  variant: "tile";

  /**
   * The items for the tile variant
   */
  items: TileItem[];
}

/**
 * Props specific to the text variant
 */
interface TextVariantProps {
  /**
   * The visual variant of the checkbox group.
   * `text`: Simple checkboxes with text labels (Checkbox)
   */
  variant: "text";

  /**
   * The items for the text variant
   */
  items: TextItem[];
}

/**
 * Props specific to the compact variant
 */
interface CompactVariantProps {
  /**
   * The visual variant of the checkbox group.
   * `compact`: Checkboxes in a bordered container with dividers
   */
  variant: "compact";

  /**
   * The items for the compact variant
   */
  items: CompactItem[];
}

/**
 * Discriminated union of all variant props
 */
type CheckboxFieldsetVariantProps =
  | TileVariantProps
  | TextVariantProps
  | CompactVariantProps;

/**
 * Custom props for CheckboxFieldset (non-variant specific)
 */
interface CheckboxFieldsetCustomProps {
  /**
   * The legend configuration (acts as the accessible name for the checkbox group).
   * Internally rendered as a legend element for proper fieldset semantics.
   */
  legend?: CheckboxFieldsetLegend;

  /**
   * The hint configuration (displayed below the legend)
   */
  hint?: CheckboxFieldsetHint;

  /**
   * The validation message configuration (displayed below the legend/hint, before the checkbox group)
   */
  validationMessage?: CheckboxFieldsetValidationMessage;

  /**
   * Whether a selection is required. Adds required indicator to legend and sets aria-required.
   */
  required?: boolean;

  /**
   * Whether all checkboxes in the group are disabled.
   */
  disabled?: boolean;

  /**
   * Whether the checkbox group is read-only.
   */
  readOnly?: boolean;
}

// Keys to omit from CheckboxGroupProps (including is-prefixed props we're replacing and orientation)
type AriaPropsToOmit =
  | "children"
  | "isRequired"
  | "isDisabled"
  | "isReadOnly"
  | "orientation";

/**
 * Variant-specific prop keys
 */
type VariantPropKeys =
  | keyof TileVariantProps
  | keyof TextVariantProps
  | keyof CompactVariantProps;

/**
 * Base props shared by all variants (Aria props minus omitted + custom props)
 */
type CheckboxFieldsetBaseProps = Omit<
  CheckboxGroupProps,
  AriaPropsToOmit | VariantPropKeys
> &
  CheckboxFieldsetCustomProps;

export type CheckboxFieldsetProps = CheckboxFieldsetBaseProps &
  CheckboxFieldsetVariantProps;

/**
 * Renders items based on the variant.
 * Accepts the full props to preserve TypeScript's discriminated union narrowing.
 */
const renderItems = (props: CheckboxFieldsetProps): React.ReactNode => {
  switch (props.variant) {
    case "tile":
      return props.items.map((item) => (
        <CheckboxTile key={item.value} {...item} />
      ));

    case "text":
      return props.items.map((item) => (
        <Checkbox
          key={item.value}
          {...item}
          label={{ variant: "normal", ...item.label }}
        />
      ));

    case "compact":
      return props.items.map((item) => (
        <_CheckboxCompact key={item.value} {...item} hideFocusRing />
      ));
  }
};

/**
 * A fieldset-like container for a group of checkboxes with accessible labeling.
 *
 * This component wraps React Aria's CheckboxGroup to provide:
 * - Proper checkbox group semantics
 * - Accessible name from the legend (rendered as a legend internally)
 * - `aria-describedby` for hint text
 * - `aria-invalid` when validation message has variant="invalid"
 * - `aria-required` when required is true
 * - Full keyboard navigation
 *
 * @example
 * // Tile variant
 * <CheckboxFieldset
 *   variant="tile"
 *   legend={{ children: "Select features" }}
 *   value={selectedFeatures}
 *   onChange={setSelectedFeatures}
 *   items={[
 *     { value: "feature1", label: { children: "Feature 1" }, hint: { children: "Description" } },
 *     { value: "feature2", label: { children: "Feature 2" }, hint: { children: "Description" } },
 *   ]}
 * />
 *
 * @example
 * // Text variant
 * <CheckboxFieldset
 *   variant="text"
 *   legend={{ children: "Notification preferences" }}
 *   value={selectedNotifications}
 *   onChange={setSelectedNotifications}
 *   items={[
 *     { value: "email", label: { children: "Email" } },
 *     { value: "sms", label: { children: "SMS" } },
 *   ]}
 * />
 *
 * @example
 * // Compact variant
 * <CheckboxFieldset
 *   variant="compact"
 *   legend={{ children: "Select options" }}
 *   value={selectedOptions}
 *   onChange={setSelectedOptions}
 *   items={[
 *     { value: "option1", label: { children: "Option 1" } },
 *     { value: "option2", label: { children: "Option 2" } },
 *   ]}
 * />
 *
 * @see https://react-spectrum.adobe.com/react-aria/CheckboxGroup.html
 */
export const CheckboxFieldset = forwardRef<
  HTMLDivElement,
  CheckboxFieldsetProps
>((props, ref) => {
  const {
    variant: _variant,
    items: _items,
    legend,
    hint,
    validationMessage,
    className,
    required,
    disabled,
    readOnly,
    ...checkboxGroupProps
  } = props;

  const generatedId = useId();
  const hintId = hint ? `${generatedId}-hint` : undefined;
  const validationMessageId = validationMessage
    ? `${generatedId}-validation`
    : undefined;

  // Build aria-describedby from hint and validation message IDs
  const describedByIds = [hintId, validationMessageId].filter(
    Boolean
  ) as string[];
  const ariaDescribedBy =
    describedByIds.length > 0 ? describedByIds.join(" ") : undefined;

  // Determine if the checkbox group is in an invalid state
  const isInvalid = validationMessage?.variant === "invalid";

  // Determine required state: use legend.required if explicitly set, otherwise fall back to required
  const legendRequired = legend?.required ?? required ?? false;

  return (
    <CheckboxGroup
      ref={ref}
      className={clsx(styles.checkboxFieldset, className)}
      invalid={isInvalid}
      {...(required !== undefined && { required })}
      {...(disabled !== undefined && { disabled })}
      {...(readOnly !== undefined && { readOnly })}
      {...(ariaDescribedBy !== undefined && {
        "aria-describedby": ariaDescribedBy,
      })}
      {...checkboxGroupProps}
    >
      {(legend || hint) && (
        <div className={styles.legendHintStack}>
          {legend && (
            <Legend {...legend} asChild required={legendRequired}>
              <AriaLabel>{legend.children}</AriaLabel>
            </Legend>
          )}
          {hint && (
            <Text elementType="div" slot="description" id={hintId}>
              <Hint {...hint} />
            </Text>
          )}
        </div>
      )}
      {validationMessage && (
        <div className={styles.validationMessageContainer}>
          <ValidationMessage id={validationMessageId} {...validationMessage}>
            {validationMessage.children}
          </ValidationMessage>
        </div>
      )}
      <div
        className={styles.checkboxGroupContainer({ variant: props.variant })}
      >
        {renderItems(props)}
      </div>
    </CheckboxGroup>
  );
});

CheckboxFieldset.displayName = "CheckboxFieldset";
