import type { CheckboxTileProps } from "../CheckboxTile";
import type { CheckboxProps } from "../Checkbox";
import type { CheckboxCompactProps } from "./components/_CheckboxCompact";

export const CheckboxFieldsetVariants = ["tile", "text", "compact"] as const;
export type CheckboxFieldsetVariant = (typeof CheckboxFieldsetVariants)[number];

export const DEFAULT_CHECKBOX_FIELDSET_VARIANT: CheckboxFieldsetVariant =
  "tile";

/**
 * Item shape for the tile variant.
 * Uses CheckboxTile internally.
 */
export type TileItem = Omit<CheckboxTileProps, "hideFocusRing">;

/**
 * Item shape for the text variant.
 * Uses Checkbox internally.
 */
export type TextItem = Omit<CheckboxProps, "hideFocusRing">;

/**
 * Item shape for the compact variant.
 * Uses internal _CheckboxCompact component.
 */
export type CompactItem = Omit<CheckboxCompactProps, "hideFocusRing">;
